"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[835],{7247:e=>{e.exports=JSON.parse('{"functions":[{"name":"RegisterPanel","desc":"Register a dockable panel, a named view usually built with `ctx.Window` inside its `Open`.\\nPanels are surfaced by the `panels` command and opened with `open <name>`.","params":[{"name":"panel","desc":"","lua_type":"Panel"}],"returns":[{"desc":"","lua_type":"Panel"}],"function_type":"static","tags":["Commands"],"source":{"line":191,"path":"src/init.luau"}},{"name":"RegisterExtension","desc":"Register a whole extension: its `Commands` and `Types` are wired into Karet, its `Panels`\\nbecome openable, and `Init(Karet)` runs once. This is the unit that makes Karet a platform.","params":[{"name":"ext","desc":"","lua_type":"Extension"}],"returns":[{"desc":"","lua_type":"Extension"}],"function_type":"static","tags":["Commands"],"source":{"line":204,"path":"src/init.luau"}},{"name":"Panels","desc":"Every registered panel.","params":[],"returns":[{"desc":"","lua_type":"{Panel}"}],"function_type":"static","tags":["Commands"],"source":{"line":239,"path":"src/init.luau"}},{"name":"SetVar","desc":"Set a shell variable. The same value is readable in the shell as `@name`, since this writes\\nstraight into the evaluator\'s scope ([Karet.Env]). Seed defaults before [Karet.Start].","params":[{"name":"name","desc":"","lua_type":"string"},{"name":"value","desc":"","lua_type":"any"}],"returns":[],"function_type":"static","tags":["Variables"],"source":{"line":262,"path":"src/init.luau"}},{"name":"GetVar","desc":"Read a shell variable (the `@name` store).","params":[{"name":"name","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"any"}],"function_type":"static","tags":["Variables"],"source":{"line":274,"path":"src/init.luau"}},{"name":"Run","desc":"Run a line through the shell (alias-expanded), exactly as if it had been typed. Returns the\\nchain result `{ ok, returns?, error? }`, or `nil` before [Karet.Start] has run.","params":[{"name":"line","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"any"}],"function_type":"static","tags":["Output"],"source":{"line":291,"path":"src/init.luau"}},{"name":"Toast","desc":"Pop a transient toast notification on the active terminal. No-op on the server or before a\\nterminal exists. `group` keys into the theme like any output group. Handy for extensions and\\nadmin events.","params":[{"name":"text","desc":"","lua_type":"string"},{"name":"opts","desc":"","lua_type":"{ group: string?, title: string?, duration: number? }?"}],"returns":[],"function_type":"static","tags":["Output"],"realm":["Client"],"source":{"line":314,"path":"src/init.luau"}},{"name":"UseProfile","desc":"Switch the active profile (history, theme, saved kavs, aliases, functions), creating it if\\nit doesn\'t exist yet. [Karet.Profile] then points at it.","params":[{"name":"name","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"Profile"}],"function_type":"static","tags":["Setup"],"source":{"line":352,"path":"src/init.luau"}},{"name":"Command","desc":"Define and register a command. The one way to add a command:\\n\\n```lua\\ntype BanArgs = { target: Player, reason: string? }\\n\\nKaret.Command(\\"ban\\", {\\n    Network = \\"Server\\",\\n    Permission = \\"Admin\\",\\n    Args = {\\n        { Name = \\"target\\", Type = \\"Player\\" },\\n        { Name = \\"reason\\", Type = \\"String\\", Required = false },\\n    },\\n    Server = function(ctx: Karet.Context<BanArgs>)\\n        -- ctx.Args.target is typed as Player, ctx.Args.reason as string?\\n    end,\\n})\\n```\\n\\nDeclare the arg record (`BanArgs` here) and annotate the handler\'s `ctx` with\\n`Karet.Context<...>` to get fully typed, autocompleted `ctx.Args`. See\\n[the commands guide](/docs/commands) for the full shape.","params":[{"name":"name","desc":"","lua_type":"string"},{"name":"def","desc":"","lua_type":"CommandDefinition"}],"returns":[{"desc":"","lua_type":"CommandDefinition"}],"function_type":"static","tags":["Commands"],"source":{"line":398,"path":"src/init.luau"}},{"name":"DefineType","desc":"Register a custom argument type (a la Cmdr). Types parse and validate the raw token into a\\ntyped value, and can supply autocomplete.","params":[{"name":"name","desc":"","lua_type":"string"},{"name":"def","desc":"","lua_type":"TypeDefinition"}],"returns":[],"function_type":"static","tags":["Commands"],"source":{"line":412,"path":"src/init.luau"}},{"name":"List","desc":"The names of every registered command.","params":[],"returns":[{"desc":"","lua_type":"{string}"}],"function_type":"static","tags":["Commands"],"source":{"line":423,"path":"src/init.luau"}},{"name":"Get","desc":"A single command\'s definition, or nil.","params":[{"name":"name","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"CommandDefinition?"}],"function_type":"static","tags":["Commands"],"source":{"line":435,"path":"src/init.luau"}},{"name":"SetRoleHook","desc":"Decide a player\'s role. Roles are compared against a command\'s `Permission` using the rank\\nordering from [Karet.SetRoles].","params":[{"name":"fn","desc":"","lua_type":"(player: Player) -> string"}],"returns":[],"function_type":"static","tags":["Permissions"],"realm":["Server"],"source":{"line":452,"path":"src/init.luau"}},{"name":"SetAuthHook","desc":"A per-command gate. Return `true` to allow, `false` to deny, or `nil` to fall through to the\\nnormal role check.","params":[{"name":"fn","desc":"","lua_type":"(player: Player, command: string) -> boolean?"}],"returns":[],"function_type":"static","tags":["Permissions"],"realm":["Server"],"source":{"line":465,"path":"src/init.luau"}},{"name":"SetGroupHook","desc":"Resolve a player\'s numeric rank (e.g. a Roblox group rank), for commands that compare against\\na number.","params":[{"name":"fn","desc":"","lua_type":"(player: Player) -> number"}],"returns":[],"function_type":"static","tags":["Permissions"],"realm":["Server"],"source":{"line":478,"path":"src/init.luau"}},{"name":"AllowPlayer","desc":"Allowlist a userId outright.","params":[{"name":"userId","desc":"","lua_type":"number"}],"returns":[],"function_type":"static","tags":["Permissions"],"realm":["Server"],"source":{"line":490,"path":"src/init.luau"}},{"name":"DenyPlayer","desc":"Denylist a userId outright.","params":[{"name":"userId","desc":"","lua_type":"number"}],"returns":[],"function_type":"static","tags":["Permissions"],"realm":["Server"],"source":{"line":502,"path":"src/init.luau"}},{"name":"SetDefaultRole","desc":"The role players get when no role hook is set or it returns nothing.","params":[{"name":"role","desc":"","lua_type":"string"}],"returns":[],"function_type":"static","tags":["Permissions"],"realm":["Server"],"source":{"line":514,"path":"src/init.luau"}},{"name":"SetRoles","desc":"Define the role -> rank ordering used for `Permission` comparisons, e.g.\\n`{ User = 0, Mod = 50, Admin = 100 }`.","params":[{"name":"ranks","desc":"","lua_type":"{ [string]: number }"}],"returns":[],"function_type":"static","tags":["Permissions"],"realm":["Server"],"source":{"line":527,"path":"src/init.luau"}},{"name":"PreExecute","desc":"Run before every command. Return `false` to cancel it.","params":[{"name":"fn","desc":"","lua_type":"(ctx: Context) -> any?"}],"returns":[],"function_type":"static","tags":["Middleware"],"source":{"line":542,"path":"src/init.luau"}},{"name":"PostExecute","desc":"Run after every command with its result.","params":[{"name":"fn","desc":"","lua_type":"(ctx: Context, result: any) -> ()"}],"returns":[],"function_type":"static","tags":["Middleware"],"source":{"line":553,"path":"src/init.luau"}},{"name":"OnErr","desc":"Run when a command errors.","params":[{"name":"fn","desc":"","lua_type":"(ctx: Context, err: any) -> ()"}],"returns":[],"function_type":"static","tags":["Middleware"],"source":{"line":564,"path":"src/init.luau"}},{"name":"OnConnect","desc":"Run when a player joins.","params":[{"name":"fn","desc":"","lua_type":"(player: Player) -> ()"}],"returns":[],"function_type":"static","tags":["Middleware"],"realm":["Server"],"source":{"line":576,"path":"src/init.luau"}},{"name":"Start","desc":"Boot Karet. On the client this builds and wires the terminal and the command evaluator and\\nreturns the [Terminal]; on the server it stands up the networking listener and the auth\\npipeline and returns `nil`. The same call works in both realms.\\n\\n```lua\\nKaret.Start({ Toggle = \\"Semicolon\\", Theme = \\"tokyonight\\", Kaveat = true })\\n```","params":[{"name":"opts","desc":"","lua_type":"StartConfig?"}],"returns":[{"desc":"","lua_type":"Terminal?"}],"function_type":"static","tags":["Setup"],"source":{"line":1395,"path":"src/init.luau"}}],"properties":[{"name":"Version","desc":"The Karet version string, e.g. `\\"0.1.0\\"`.","lua_type":"string","readonly":true,"source":{"line":123,"path":"src/init.luau"}}],"types":[{"name":"StartConfig","desc":"The options table passed to [Karet.Start]. The same shape is used on both realms; each\\nrealm reads the options that apply to it.","fields":[{"name":"Toggle","lua_type":"ToggleSpec?","desc":"key / shortcut to open the terminal, e.g. \\"Semicolon\\" or \\"LeftControl+Semicolon\\""},{"name":"Theme","lua_type":"(string | ThemePalette)?","desc":"a built-in theme name or a palette"},{"name":"Placement","lua_type":"(\\"Window\\" | \\"Top\\" | \\"Bottom\\" | \\"Middle\\")?","desc":"where the window / bar sits"},{"name":"Compact","lua_type":"boolean?","desc":"single-line command bar instead of the full window"},{"name":"Draggable","lua_type":"boolean?","desc":"drag the Window-placement terminal by its title bar"},{"name":"Parent","lua_type":"Instance?","desc":"where to mount (defaults to PlayerGui)"},{"name":"Size","lua_type":"UDim2?","desc":"override the window size"},{"name":"Position","lua_type":"UDim2?","desc":"override the window position"},{"name":"Kaveat","lua_type":"boolean?","desc":"enable the Kaveat editor"},{"name":"PromptType","lua_type":"(\\"text\\" | \\"window\\")?","desc":"how Dangerous commands confirm: terminal y/N or an Iris modal"},{"name":"Persist","lua_type":"boolean?","desc":"save / load the profile via Pik DataStores"},{"name":"Admin","lua_type":"boolean?","desc":"enable the moderation suite (kick / ban / mute / audit + dashboard)"},{"name":"BuiltIns","lua_type":"boolean?","desc":"register built-in commands (default true)"},{"name":"Commands","lua_type":"(Instance | { Instance } | { CommandDefinition<any> })?","desc":"auto-load command modules: a Folder (required recursively), a list of ModuleScripts, or ready-made defs"},{"name":"DefaultRole","lua_type":"string?","desc":"server: default role for players"},{"name":"RateLimit","lua_type":"RateLimit?","desc":"server: rate limiting (reserved)"},{"name":"KaveatExec","lua_type":"(boolean | (player: Player) -> boolean)?","desc":"server: allow kaveat to run code"}],"source":{"line":80,"path":"src/init.luau"}}],"name":"Karet","desc":"The Karet entry point. `require` it on both realms and call [Karet.Start] once per realm:\\n\\n```lua\\nlocal Karet = require(game.ReplicatedStorage.Karet)\\nKaret.Start({ Toggle = \\"Semicolon\\", Theme = \\"tokyonight\\", Kaveat = true })\\n```\\n\\n`Karet` is the product, the terminal surface, and the shell grammar that runs inside it.\\nRegister your own commands with [Karet.Command], gate them with the permission hooks, and\\nhook the lifecycle with the middleware hooks. The shell, theme engine, editor and rich\\noutput toolkit hang off this table too ([Karet.Shell], [Karet.Theme], ...).","source":{"line":115,"path":"src/init.luau"}}')}}]);